#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Basename qw(dirname);
use Cwd qw(getcwd);

my $MINIGIT_DIR = '.minigit';
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $COMMITS_DIR = "$MINIGIT_DIR/commits";
my $INDEX_FILE  = "$MINIGIT_DIR/index";
my $HEAD_FILE   = "$MINIGIT_DIR/HEAD";

sub minihash {
    my ($data) = @_;
    # Use Math::BigInt to handle 64-bit unsigned arithmetic
    # Actually, Perl can handle 64-bit integers if built with 64-bit support
    # But to be safe with mod 2^64, we use the & operator with 0xFFFFFFFFFFFFFFFF
    no warnings 'portable';
    my $h = 1469598103934665603;
    my $mul = 1099511628211;
    my $mask = 0xFFFFFFFFFFFFFFFF;
    for my $b (unpack('C*', $data)) {
        $h = ($h ^ $b) & $mask;
        # Multiply with overflow handling
        $h = _mul64($h, $mul);
    }
    return sprintf('%016x', $h);
}

sub _mul64 {
    my ($a, $b) = @_;
    # Split into 32-bit halves to avoid overflow
    my $a_lo = $a & 0xFFFFFFFF;
    my $a_hi = ($a >> 32) & 0xFFFFFFFF;
    my $b_lo = $b & 0xFFFFFFFF;
    my $b_hi = ($b >> 32) & 0xFFFFFFFF;

    my $lo_lo = $a_lo * $b_lo;
    my $cross1 = $a_hi * $b_lo;
    my $cross2 = $a_lo * $b_hi;

    # We only need lower 64 bits
    my $lo = $lo_lo & 0xFFFFFFFF;
    my $carry = ($lo_lo >> 32) & 0xFFFFFFFF;
    my $mid = ($carry + ($cross1 & 0xFFFFFFFF) + ($cross2 & 0xFFFFFFFF)) & 0xFFFFFFFF;

    # Perl may use native 64-bit, but let's use the check approach
    # Actually, let's just use use integer or bigint
    # Simplest: if perl has 64-bit ints, just do it directly
    return (($mid << 32) | $lo);
}

sub read_file {
    my ($path) = @_;
    open(my $fh, '<', $path) or return '';
    local $/;
    my $content = <$fh>;
    close($fh);
    return defined $content ? $content : '';
}

sub read_file_raw {
    my ($path) = @_;
    open(my $fh, '<:raw', $path) or return '';
    local $/;
    my $content = <$fh>;
    close($fh);
    return defined $content ? $content : '';
}

sub write_file {
    my ($path, $content) = @_;
    open(my $fh, '>', $path) or die "Cannot write $path: $!\n";
    print $fh $content;
    close($fh);
}

sub write_file_raw {
    my ($path, $content) = @_;
    open(my $fh, '>:raw', $path) or die "Cannot write $path: $!\n";
    print $fh $content;
    close($fh);
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path($OBJECTS_DIR);
    make_path($COMMITS_DIR);
    write_file($INDEX_FILE, '');
    write_file($HEAD_FILE, '');
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -e $file) {
        print "File not found\n";
        exit 1;
    }

    my $content = read_file_raw($file);
    my $hash = minihash($content);

    write_file_raw("$OBJECTS_DIR/$hash", $content);

    # Read current index
    my $index_content = read_file($INDEX_FILE);
    my @entries = grep { $_ ne '' } split(/\n/, $index_content);

    # Add if not already present
    unless (grep { $_ eq $file } @entries) {
        push @entries, $file;
    }

    write_file($INDEX_FILE, join("\n", @entries) . "\n");
}

sub cmd_commit {
    my ($message) = @_;

    my $index_content = read_file($INDEX_FILE);
    my @entries = grep { $_ ne '' } split(/\n/, $index_content);

    if (@entries == 0) {
        print "Nothing to commit\n";
        exit 1;
    }

    # Sort filenames
    @entries = sort @entries;

    # Get parent
    my $head = read_file($HEAD_FILE);
    chomp $head if defined $head;
    my $parent = (defined $head && $head ne '') ? $head : 'NONE';

    # Get timestamp
    my $timestamp = time();

    # Build file list with hashes
    my @file_lines;
    for my $file (@entries) {
        my $content = read_file_raw($file);
        my $hash = minihash($content);
        push @file_lines, "$file $hash";
    }

    # Build commit content
    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    $commit_content .= join("\n", @file_lines) . "\n";

    my $commit_hash = minihash($commit_content);

    write_file("$COMMITS_DIR/$commit_hash", $commit_content);
    write_file($HEAD_FILE, $commit_hash);
    write_file($INDEX_FILE, '');

    print "Committed $commit_hash\n";
}

sub cmd_log {
    my $head = read_file($HEAD_FILE);
    chomp $head if defined $head;

    if (!defined $head || $head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    while ($current ne '' && $current ne 'NONE') {
        my $commit_file = "$COMMITS_DIR/$current";
        unless (-f $commit_file) {
            last;
        }

        my $content = read_file($commit_file);
        my ($parent, $timestamp, $message);

        for my $line (split(/\n/, $content)) {
            if ($line =~ /^parent:\s*(.*)$/) {
                $parent = $1;
            } elsif ($line =~ /^timestamp:\s*(.*)$/) {
                $timestamp = $1;
            } elsif ($line =~ /^message:\s*(.*)$/) {
                $message = $1;
            }
        }

        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";
        print "\n";

        $current = (defined $parent && $parent ne 'NONE') ? $parent : '';
    }
}

# Main
my $command = shift @ARGV;

unless (defined $command) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($command eq 'init') {
    cmd_init();
} elsif ($command eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($command eq 'commit') {
    # Parse -m "message"
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    if (!defined $flag || $flag ne '-m' || !defined $message) {
        print "Usage: minigit commit -m \"<message>\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($command eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $command\n";
    exit 1;
}

